syntax = "proto3";

package vector.flow;

option go_package = "github.com/Bearil/vector-srv/api/proto";

service FlowService {
  rpc Stream (StreamRequest) returns (stream StreamResponse);
}

message StreamRequest {
  string session_id = 1;
  string user_message = 2;
  string project_root = 3;
}

message StreamResponse {
  string event_type = 1;
  string content = 2;
  string tool_name = 3;
  string tool_arguments = 4;
  string tool_result = 5;
  bool is_final = 6;
}

package grpc

import (
	"context"
	"log/slog"

	pb "github.com/Bearil/vector-srv/api/proto"
	"github.com/Bearil/vector-srv/internal/usecase/answer_question"
)

type FlowHandler struct {
	pb.UnimplementedFlowServiceServer
	usecase *answer_question.Usecase
}

func NewFlowHandler(uc *answer_question.Usecase) *FlowHandler {
	return &FlowHandler{usecase: uc}
}

func (h *FlowHandler) Stream(req *pb.StreamRequest, stream pb.FlowService_StreamServer) error {
	ctx := stream.Context()
	slog.InfoContext(ctx, "stream started", "session_id", req.GetSessionId())
	return nil
}

package grpc

import (
	"fmt"
	"net"

	pb "github.com/Bearil/vector-srv/api/proto"
	"google.golang.org/grpc"
)

type Server struct {
	grpcServer *grpc.Server
	listener   net.Listener
	port       int
}

func NewServer(port int) (*Server, error) {
	lis, err := net.Listen("tcp", fmt.Sprintf(":%d", port))
	if err != nil {
		return nil, fmt.Errorf("listen: %w", err)
	}
	s := grpc.NewServer()
	pb.RegisterFlowServiceServer(s, nil)
	return &Server{grpcServer: s, listener: lis, port: port}, nil
}

package main

import (
	"log/slog"
	"os"

	"github.com/Bearil/vector-srv/pkg/config"
	grpcserver "github.com/Bearil/vector-srv/internal/delivery/grpc"
)

func main() {
	cfg, err := config.Load("config.yaml")
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}
	server, err := grpcserver.NewServer(cfg.Port)
	if err != nil {
		slog.Error("server error", "error", err)
		os.Exit(1)
	}
	server.Start()
}

